import { useEffect, useState } from "react";
import { userService } from "../services/api";
import MessageBanner from "../components/MessageBanner";

const initialForm = {
  name: "",
  email: ""
};

const UsersPage = () => {
  const [users, setUsers] = useState([]);
  const [form, setForm] = useState(initialForm);
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  const loadUsers = async () => {
    try {
      setError("");
      const res = await userService.getAll();
      setUsers(res.data || []);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to fetch users");
    }
  };

  useEffect(() => {
    loadUsers();
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      setError("");
      setMessage("");
      await userService.create(form);
      setForm(initialForm);
      setMessage("User added successfully");
      await loadUsers();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to add user");
    }
  };

  const handleDelete = async (id) => {
    try {
      setError("");
      setMessage("");
      await userService.remove(id);
      setMessage("User deleted successfully");
      await loadUsers();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to delete user");
    }
  };

  return (
    <div>
      <h2 className="text-2xl font-semibold mb-6">Users</h2>
      <MessageBanner message={message} />
      <MessageBanner message={error} variant="error" />

      <form onSubmit={handleSubmit} className="bg-white shadow rounded-lg p-4 mb-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
          <input
            className="border rounded px-3 py-2"
            name="name"
            placeholder="Name"
            value={form.name}
            onChange={handleChange}
            required
          />
          <input
            className="border rounded px-3 py-2"
            name="email"
            type="email"
            placeholder="Email"
            value={form.email}
            onChange={handleChange}
            required
          />
        </div>
        <button
          type="submit"
          className="mt-4 bg-slate-800 text-white px-4 py-2 rounded hover:bg-slate-700"
        >
          Add User
        </button>
      </form>

      <div className="bg-white shadow rounded-lg overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-100">
            <tr>
              <th className="p-3">Name</th>
              <th className="p-3">Email</th>
              <th className="p-3">Role</th>
              <th className="p-3">Action</th>
            </tr>
          </thead>
          <tbody>
            {users.map((user) => (
              <tr key={user._id} className="border-t">
                <td className="p-3">{user.name}</td>
                <td className="p-3">{user.email}</td>
                <td className="p-3">{user.role}</td>
                <td className="p-3">
                  {user.role !== "admin" ? (
                    <button
                      type="button"
                      className="bg-red-600 text-white px-3 py-1 rounded hover:bg-red-500"
                      onClick={() => handleDelete(user._id)}
                    >
                      Delete
                    </button>
                  ) : (
                    <span className="text-gray-500 text-sm">Protected</span>
                  )}
                </td>
              </tr>
            ))}
            {!users.length && (
              <tr>
                <td className="p-3 text-gray-500" colSpan="4">
                  No users available.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default UsersPage;
